 {"id":"franken_networkx-a2m","title":"Add hypothesis property tests for graph expansion metrics","description":"Add hypothesis-based property tests for volume, boundary_expansion, conductance, edge_expansion, node_expansion, mixing_expansion, and connectivity functions. These should cross-validate against NetworkX reference on randomly generated graphs.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-03-19T03:40:30.273898385Z","created_by":"ubuntu","updated_at":"2026-03-19T03:42:07.088883202Z","closed_at":"2026-03-19T03:42:07.087835071Z","close_reason":"Added 11 hypothesis property tests: volume, conductance, edge/node/boundary/mixing expansion invariants, non-edges count, k-edge-connected monotonicity, average node connectivity bounds, Whitney's theorem","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"franken_networkx-a3va","title":"parity: filtered graph views adj should preserve atlas-view mapping helpers","description":"restricted_view(...) and subgraph_view(...) currently expose adj mapping helpers whose values are internal _FilteredNeighborMap objects in FrankenNetworkX. list(view.adj.items()) and list(view.adj.values()) therefore return implementation-specific wrappers instead of the AtlasView-style filtered adjacency values NetworkX exposes. Match the upstream adj mapping-helper contract on filtered graph views.","status":"open","priority":2,"issue_type":"task","created_at":"2026-04-21T09:35:03.718527047Z","created_by":"ubuntu","updated_at":"2026-04-21T09:35:03.718527047Z","source_repo":".","compaction_level":0,"original_size":0}
